solutions.python:
import sys
class Solution:
  def solve(self, nums, target):
    low = 0
    high = len(nums) - 1
    while low <= high:
      mid = (low + high) // 2
      if nums[mid] == target:
        return True
      elif nums[mid] < target:
        low = mid + 1
      else:
        high = mid - 1
    return False
nums = list(map(int, sys.stdin.readline().split()))
target = int(sys.stdin.readline())
obj = Solution()
two = obj.solve(nums, target)
print(two)

