#include <algorithm>
#include <iostream>
using namespace std;
class Solution {
public:
  bool solve(vector<int>& nums) {
    int n = nums.size();
    int low = 0, high = n - 1;
    while (low <= high) {
      int mid = (low + high) / 2;
      if (nums[mid] == target)
        return true;
      else if (nums[mid] < target)
        low = mid + 1;
      else
        high = mid - 1;
    }
    return false;
  }
};
int main() {
  int n;
  cin >> n;
  vector<int> nums(n);
  for (int i = 0; i < n; i++)
    cin >> nums[i];
  int target;
  cin >> target;
  Solution obj;
  bool two = obj.solve(nums);
  cout << two << endl;
  return 0;
}
